mapper.select:
SELECT ID, WORDS_TITLE, WORDS_DETAIL, WORDS_IMAGE, WORDS_TYPE, EDU_VIDEO_ID
FROM TBL_WORDS
WHERE ID = #{id}

mapper.update:
UPDATE TBL_WORDS
SET WORDS_TITLE = #{wordsTitle}, WORDS_DETAIL = #{wordsDetail}, WORDS_IMAGE = #{wordsImage}, WORDS_TYPE = #{wordsType}, EDU_VIDEO_ID = #{eduVideoId}
WHERE ID = #{id}
